#include<stdio.h>
int tails[100001],sz=0;
int lower_bound(int*a,int n,int x){int lo=0,hi=n;while(lo<hi){int m=(lo+hi)/2;if(a[m]<x)lo=m+1;else hi=m;}return lo;}
int main(){int n;scanf("%d",&n);int x;for(int i=0;i<n;i++){scanf("%d",&x);int pos=lower_bound(tails,sz,x);tails[pos]=x;if(pos==sz)sz++;}printf("%d\n",sz);}

