#include<stdio.h>
int dp[100001];
int main(){int n;scanf("%d",&n);int a[100001];for(int i=0;i<n;i++)scanf("%d",&a[i]);int ans=1;for(int i=0;i<n;i++){dp[i]=1;for(int j=0;j<i;j++)if(a[j]<a[i]&&dp[j]+1>dp[i])dp[i]=dp[j]+1;if(dp[i]>ans)ans=dp[i];}printf("%d\n",ans);}
